function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const TOKEN = '7959589740:AAGM9gvS35rBVhNMmX1PcEuQsaVcUJNSaKs';
const CHAT_ID = '-1004292409396';

const raw = items[0].json;
const allDeals = raw.list || [];

// Verifica se o deal é da Steam pelo shop name
function isSteamDeal(item) {
  const shopName = (item.deal && item.deal.shop && item.deal.shop.name)
    ? item.deal.shop.name.toLowerCase()
    : '';
  return shopName === 'steam';
}

// Filtra: só jogos Steam com preço base > 0
const deals = allDeals
  .filter(item => item.type === 'game')
  .filter(item => isSteamDeal(item))
  .filter(item => {
    const d = item.deal || {};
    const regularCents = (d.regular && d.regular.amountInt != null) ? d.regular.amountInt : null;
    return regularCents != null && regularCents > 0;
  });

// Ordena por maior % de desconto (já vem ordenado pela API, mas garantimos aqui)
deals.sort((a, b) => {
  const cutA = (a.deal && a.deal.cut != null) ? a.deal.cut : 0;
  const cutB = (b.deal && b.deal.cut != null) ? b.deal.cut : 0;
  return cutB - cutA;
});

const result = [];

// Cabeçalho
result.push({
  json: {
    telegramUrl: `https://api.telegram.org/bot${TOKEN}/sendMessage`,
    bodyString: JSON.stringify({
      chat_id: CHAT_ID,
      text: '🎮 <b>MELHORES PROMOÇÕES DE JOGOS PC — STEAM</b> 🎮\n🏪 Ordenado pelos maiores descontos!\n🕐 ' + new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' }) + '\n────────────────────────',
      parse_mode: 'HTML',
      disable_web_page_preview: true
    })
  }
});

for (const item of deals) {
  const title = item.title || 'Sem título';
  const d = item.deal || {};

  const cut = d.cut != null ? Math.round(d.cut) : 0;
  const priceCents = (d.price && d.price.amountInt != null) ? d.price.amountInt : null;
  const regularCents = (d.regular && d.regular.amountInt != null) ? d.regular.amountInt : null;
  const currency = (d.price && d.price.currency) ? d.price.currency : 'BRL';
  const sym = currency === 'BRL' ? 'R$' : (currency === 'USD' ? 'US$' : currency + ' ');

  let priceText;
  if (priceCents === 0) {
    priceText = '🎁 <b>GRATUITO TEMPORARIAMENTE</b>';
  } else if (priceCents != null && regularCents != null) {
    const priceFmt = `${sym}${(priceCents / 100).toFixed(2)}`;
    const regularFmt = `${sym}${(regularCents / 100).toFixed(2)}`;
    priceText = `💰 De: ${regularFmt} → <b>${priceFmt}</b>`;
  } else if (priceCents != null) {
    priceText = `💰 Por: <b>${sym}${(priceCents / 100).toFixed(2)}</b>`;
  } else {
    priceText = '💰 Preço não disponível';
  }

  const url = d.url || null;
  const thumb = item.assets
    ? (item.assets.banner300 || item.assets.banner145 || item.assets.boxart || null)
    : null;

  const caption =
    `🎮 <b>${escapeHtml(title)}</b>\n` +
    `🏪 Steam\n` +
    priceText + '\n' +
    `🔥 ${cut}% OFF\n` +
    (url ? `<a href="${url}">🔗 Abrir na Steam</a>` : '');

  if (thumb) {
    result.push({
      json: {
        telegramUrl: `https://api.telegram.org/bot${TOKEN}/sendPhoto`,
        bodyString: JSON.stringify({
          chat_id: CHAT_ID,
          photo: thumb,
          caption: caption,
          parse_mode: 'HTML'
        })
      }
    });
  } else {
    result.push({
      json: {
        telegramUrl: `https://api.telegram.org/bot${TOKEN}/sendMessage`,
        bodyString: JSON.stringify({
          chat_id: CHAT_ID,
          text: caption,
          parse_mode: 'HTML',
          disable_web_page_preview: true
        })
      }
    });
  }
}

// Rodapé
result.push({
  json: {
    telegramUrl: `https://api.telegram.org/bot${TOKEN}/sendMessage`,
    bodyString: JSON.stringify({
      chat_id: CHAT_ID,
      text: '────────────────────────\n⏰ Próxima atualização em 6 horas',
      parse_mode: 'HTML'
    })
  }
});

return result;
